  "inlineSchema": "// ============================================================\n// SCHEMA - SISTEMA CLÍNICA VETERINÁRIA\n// ORM: Prisma | Banco: PostgreSQL\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================\n// USUÁRIO (login da veterinária)\n// ============================================================\nmodel Usuario {\n  id           String   @id @default(uuid())\n  nome         String\n  email        String   @unique\n  senha        String // hash bcrypt\n  crmv         String? // registro profissional\n  assinatura   String? // caminho para imagem da assinatura (impressão)\n  criadoEm     DateTime @default(now())\n  atualizadoEm DateTime @updatedAt\n\n  consultas Consulta[]\n\n  @@map(\"usuarios\")\n}\n\n// ============================================================\n// TUTOR (dono do animal)\n// ============================================================\nmodel Tutor {\n  id           String   @id @default(uuid())\n  nome         String\n  cpf          String?  @unique\n  telefone     String\n  email        String?\n  endereco     String?\n  cidade       String?\n  criadoEm     DateTime @default(now())\n  atualizadoEm DateTime @updatedAt\n\n  animais Animal[]\n\n  @@map(\"tutores\")\n}\n\n// ============================================================\n// ANIMAL (paciente)\n// ============================================================\nmodel Animal {\n  id             String    @id @default(uuid())\n  nome           String\n  especie        Especie   @default(OUTRO)\n  raca           String?\n  sexo           Sexo\n  cor            String?\n  dataNascimento DateTime?\n  peso           Float? // em kg\n  microchip      String?   @unique\n  castrado       Boolean   @default(false)\n  alergias       String? // texto livre\n  observacoes    String?\n  ativo          Boolean   @default(true)\n  criadoEm       DateTime  @default(now())\n  atualizadoEm   DateTime  @updatedAt\n\n  tutorId String\n  tutor   Tutor  @relation(fields: [tutorId], references: [id])\n\n  consultas Consulta[]\n  vacinas   Vacina[]\n\n  @@map(\"animais\")\n}\n\nenum Especie {\n  CACHORRO\n  GATO\n  AVE\n  REPTIL\n  ROEDOR\n  COELHO\n  OUTRO\n}\n\nenum Sexo {\n  MACHO\n  FEMEA\n}\n\n// ============================================================\n// CONSULTA / AGENDAMENTO\n// ============================================================\nmodel Consulta {\n  id             String          @id @default(uuid())\n  dataHora       DateTime\n  tipo           TipoConsulta    @default(CONSULTA)\n  status         StatusConsulta  @default(AGENDADA)\n  motivoVisita   String? // queixa principal\n  valor          Float?\n  formaPagamento FormaPagamento?\n  pago           Boolean         @default(false)\n  observacoes    String?\n  criadoEm       DateTime        @default(now())\n  atualizadoEm   DateTime        @updatedAt\n\n  animalId String\n  animal   Animal @relation(fields: [animalId], references: [id])\n\n  veterinarioId String\n  veterinario   Usuario @relation(fields: [veterinarioId], references: [id])\n\n  prontuario Prontuario?\n\n  itensUsados   ItemConsulta[]\n  movimentacoes MovimentacaoEstoque[]\n\n  @@map(\"consultas\")\n}\n\nenum TipoConsulta {\n  CONSULTA\n  RETORNO\n  CIRURGIA\n  EMERGENCIA\n  VACINA\n  EXAME\n  BANHO_TOSA\n}\n\nenum StatusConsulta {\n  AGENDADA\n  EM_ATENDIMENTO\n  CONCLUIDA\n  CANCELADA\n  NAO_COMPARECEU\n}\n\nenum FormaPagamento {\n  DINHEIRO\n  CARTAO_DEBITO\n  CARTAO_CREDITO\n  PIX\n  BOLETO\n}\n\n// ============================================================\n// PRONTUÁRIO (coração do sistema — o que a vet digita)\n// ============================================================\nmodel Prontuario {\n  id       String  @id @default(uuid())\n  // --- Anamnese ---\n  anamnese String? // relato do tutor / histórico\n\n  // --- Exame clínico ---\n  temperatura            Float? // °C\n  frequenciaCardiaca     Int? // bpm\n  frequenciaRespiratoria Int? // rpm\n  pesoConsulta           Float? // peso registrado na consulta (kg)\n  mucosas                String?\n  hidratacao             String?\n  linfonodos             String?\n  ausculta               String?\n  exameAbdome            String?\n  exameOrtopedico        String?\n  outrosAchados          String?\n\n  // --- Diagnóstico ---\n  diagnostico         String?\n  diagnosticoSuspeito String? // hipótese diagnóstica\n\n  // --- Exames solicitados ---\n  examesSolicitados String? // texto livre: \"Hemograma, Urinálise...\"\n  resultadosExames  String? // texto livre para colar resultados\n\n  // --- Receita / Prescrição ---\n  prescricao String? // texto livre da receita completa\n\n  // --- Tratamento ---\n  tratamento String? // procedimentos realizados na consulta\n  retorno    String? // orientação de retorno: \"em 7 dias\"\n\n  // --- Orientações ao tutor ---\n  orientacoes String?\n\n  criadoEm     DateTime @default(now())\n  atualizadoEm DateTime @updatedAt\n\n  consultaId String   @unique\n  consulta   Consulta @relation(fields: [consultaId], references: [id])\n\n  @@map(\"prontuarios\")\n}\n\n// ============================================================\n// VACINAS\n// ============================================================\nmodel Vacina {\n  id            String    @id @default(uuid())\n  nome          String // ex: \"V10\", \"Antirrábica\"\n  dataAplicacao DateTime\n  proximaDose   DateTime?\n  lote          String?\n  fabricante    String?\n  observacoes   String?\n  criadoEm      DateTime  @default(now())\n\n  animalId String\n  animal   Animal @relation(fields: [animalId], references: [id])\n\n  @@map(\"vacinas\")\n}\n\n// ============================================================\n// ESTOQUE\n// ============================================================\nmodel ItemEstoque {\n  id            String        @id @default(uuid())\n  nome          String\n  categoria     CategoriaItem @default(PRODUTO)\n  descricao     String?\n  unidade       String        @default(\"un\") // un, ml, mg, cx, fr\n  quantidade    Float         @default(0)\n  quantidadeMin Float         @default(5) // alerta de estoque baixo\n  precoCusto    Float? // preço que ela paga\n  precoVenda    Float? // preço que cobra do cliente\n  codigoBarras  String?\n  fabricante    String?\n  ativo         Boolean       @default(true)\n  criadoEm      DateTime      @default(now())\n  atualizadoEm  DateTime      @updatedAt\n\n  movimentacoes MovimentacaoEstoque[]\n  itensConsulta ItemConsulta[]\n\n  @@map(\"itens_estoque\")\n}\n\nenum CategoriaItem {\n  MEDICAMENTO\n  VACINA\n  PRODUTO // shampoo, racao, acessorio\n  MATERIAL // materiais cirurgicos, seringas\n  SERVICO_CUSTO // anestesia, outros com custo\n}\n\nmodel MovimentacaoEstoque {\n  id         String        @id @default(uuid())\n  tipo       TipoMovimento\n  quantidade Float\n  motivo     String?\n  criadoEm   DateTime      @default(now())\n\n  itemId String\n  item   ItemEstoque @relation(fields: [itemId], references: [id])\n\n  consultaId String? // se veio de uma consulta\n  consulta   Consulta? @relation(fields: [consultaId], references: [id])\n\n  @@map(\"movimentacoes_estoque\")\n}\n\nenum TipoMovimento {\n  ENTRADA // compra, reposicao\n  SAIDA // uso em consulta\n  AJUSTE // correcao manual\n  PERDA // vencimento, quebra\n}\n\nmodel ItemConsulta {\n  id            String   @id @default(uuid())\n  quantidade    Float\n  precoUnitario Float?\n  confirmado    Boolean  @default(false) // revisao antes de deduzir\n  criadoEm      DateTime @default(now())\n\n  consultaId String\n  consulta   Consulta @relation(fields: [consultaId], references: [id])\n\n  itemId String\n  item   ItemEstoque @relation(fields: [itemId], references: [id])\n\n  @@map(\"itens_consulta\")\n}\n",
  "inlineSchemaHash": "054d046d25114eebdc3497fa759e18cb5a0144c93e646f16c3f6cc7c8c4bf5ac",
